static void run_all_vectors() {
    constexpr int N = (int)(sizeof(kVectors) / sizeof(kVectors[0]));
    printf("[W-HMAC-1..%d] HMAC-SHA256 Wycheproof vectors\n", N);

    int tested = 0, skipped = 0;
    for (int i = 0; i < N; ++i) {
        const HmacVector& v = kVectors[i];

        auto key_bytes = hex_decode(v.key);
        auto msg_bytes = hex_decode(v.msg);
        auto tag_bytes = hex_decode(v.tag);

        // Compute HMAC-SHA256
        auto computed = hmac_sha256(
            key_bytes.data(), key_bytes.size(),
            msg_bytes.empty() ? nullptr : msg_bytes.data(), msg_bytes.size());

        // Tag prefix length = tagSize/8
        size_t cmp_len = (size_t)(v.tagSize / 8);
        bool tag_matches = (tag_bytes.size() == cmp_len) &&
                           (memcmp(computed.data(), tag_bytes.data(), cmp_len) == 0);

        char label[64];
        snprintf(label, sizeof(label), "tcId=%d %s", v.tcId,
                 v.valid ? "valid-tag-matches" : "invalid-tag-rejected");

        if (v.valid) {
            check(tag_matches, label);
        } else {
            // ModifiedTag: computed mac should NOT equal the provided tampered tag
            check(!tag_matches, label);
        }
        ++tested;
    }
    (void)skipped;
    printf("    tested %d/%d Wycheproof HMAC-SHA256 vectors\n", tested, N);
}

int test_wycheproof_hmac_sha256_run() {
    printf("====================================================================\n");
    printf("Wycheproof HMAC-SHA256 Test Vectors (C2SP)\n");
    printf("====================================================================\n\n");
    run_all_vectors();
    printf("\n====================================================================\n");
    printf("Result: %d passed, %d failed\n", g_pass, g_fail);
    printf("====================================================================\n");
    return (g_fail > 0) ? 1 : 0;
}

#if defined(STANDALONE_TEST)
int main() {
    return test_wycheproof_hmac_sha256_run();
}
#endif